return [{
  json: {
    source: "gmail",
    customerName: "Aisha Khan",
    customerEmail: "aisha@example.com",
    customerPhone: "",
    subject: "Need pricing and setup help",
    message: "Hi, I am interested in your automation service. Can you explain pricing, setup time, and whether you support WhatsApp inquiries?",
    sendReply: false,
    settings: {
      businessName: "Demo Automation Agency",
      businessContext: "We build self-hosted n8n automations for customer support, sales lead qualification, and operations.",
      tone: "friendly, concise, professional",
      ollamaBaseUrl: "http://host.docker.internal:11434",
      ollamaModel: "llama3.1",
      maxReplyWords: 180
    },
    knowledgeBase: [
      {"title":"Pricing","text":"Starter automation setup begins at 499 USD for one channel. Multi-channel Gmail plus WhatsApp workflows usually begin at 999 USD depending on integrations."},
      {"title":"Setup time","text":"A typical MVP setup takes 5 to 10 business days after credentials, business FAQs, and test data are ready."},
      {"title":"Channels","text":"We support Gmail, WhatsApp Business Cloud API, Google Drive knowledge lookup, and Google Sheets CRM logging."}
    ]
  }
}];

const input = $input.first()?.json ?? {};
const payload = input.body ?? input;
const now = new Date();
const runId = payload.runId || `ci_${now.getTime()}_${Math.random().toString(36).slice(2, 8)}`;
const source = String(payload.source || payload.channel || "test").toLowerCase();
const message = String(payload.message || payload.text || payload.bodyText || payload.plainText || "").trim();
const subject = String(payload.subject || payload.title || "Customer inquiry").trim();
const customerName = String(payload.customerName || payload.name || payload.customer?.name || "Customer").trim();
const customerEmail = String(payload.customerEmail || payload.email || payload.from || payload.customer?.email || "").trim();
const customerPhone = String(payload.customerPhone || payload.phone || payload.waId || payload.customer?.phone || "").trim();
const settings = payload.settings || {};
const defaultKnowledge = [
  { title: "Fallback support policy", text: "When information is missing, acknowledge the customer, ask for the missing details, and avoid inventing facts." },
  { title: "Escalation rule", text: "Escalate angry complaints, refund disputes, legal threats, payment failures, and high-value leads to a human owner." }
];
const knowledgeBase = Array.isArray(payload.knowledgeBase) ? payload.knowledgeBase : Array.isArray(payload.knowledge_base) ? payload.knowledge_base : defaultKnowledge;
const config = {
  businessName: settings.businessName || payload.businessName || "Your Business",
  businessContext: settings.businessContext || payload.businessContext || "Customer inquiry handling automation.",
  tone: settings.tone || payload.tone || "friendly, concise, professional",
  ollamaBaseUrl: String(settings.ollamaBaseUrl || payload.ollamaBaseUrl || "http://host.docker.internal:11434").replace(/\/$/, ""),
  ollamaModel: settings.ollamaModel || payload.ollamaModel || "llama3.1",
  maxReplyWords: Number(settings.maxReplyWords || payload.maxReplyWords || 180),
  allowSend: Boolean(payload.sendReply === true || payload.allowSend === true)
};
if (!message) {
  throw new Error("Missing required inquiry message. Send JSON with a message field.");
}
const contact = source === "whatsapp" ? customerPhone : customerEmail;
const state = {
  runId,
  source,
  receivedAt: now.toISOString(),
  customer: { name: customerName, email: customerEmail, phone: customerPhone, contact },
  subject,
  message,
  config,
  knowledgeBase,
  originalPayload: payload,
  trace: [{
    agent: "System",
    step: "Normalize",
    status: "ok",
    at: now.toISOString(),
    decision: `Normalized ${source} inquiry into shared state.`,
    output: { runId, source, subject, contactPresent: Boolean(contact), knowledgeItems: knowledgeBase.length }
  }],
  errors: []
};
return [{ json: { state } }];

const state = $input.first().json.state;
const system = `You are the Classifier Agent for ${state.config.businessName}. Classify one customer inquiry. Return only valid JSON. No markdown.`;
const user = {
  task: "Classify the inquiry and decide routing.",
  businessContext: state.config.businessContext,
  inquiry: { source: state.source, subject: state.subject, message: state.message, customer: state.customer },
  requiredJsonSchema: {
    inquiryType: "question|complaint|order|support_ticket|sales_lead|other",
    priority: "low|medium|high|urgent",
    sentiment: "positive|neutral|negative|angry",
    language: "string",
    needsResearch: "boolean",
    needsHuman: "boolean",
    confidence: "number 0 to 1",
    reason: "short string"
  }
};
const ollamaRequest = { model: state.config.ollamaModel, stream: false, format: "json", messages: [{ role: "system", content: system }, { role: "user", content: JSON.stringify(user) }] };
return [{ json: { state, ollamaRequest } }];

function getPreviousState() {
  try { return $items("Prepare Classifier Prompt")[0].json.state; } catch (error) { return $input.first().json.state || {}; }
}
function contentFromResponse(response) {
  if (response?.message?.content) return response.message.content;
  if (response?.response) return response.response;
  if (response?.data?.message?.content) return response.data.message.content;
  if (typeof response === "string") return response;
  return "";
}
function parseJsonLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch (error) {}
  const match = String(text).match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (error) {}
  }
  return null;
}
function fallbackClassifier(state) {
  const text = `${state.subject} ${state.message}`.toLowerCase();
  const complaint = /(angry|bad|broken|refund|cancel|complaint|not working|issue|problem|late|wrong)/.test(text);
  const order = /(order|tracking|delivery|invoice|payment|paid|ship|shipping)/.test(text);
  const sales = /(price|pricing|quote|buy|purchase|demo|interested|cost|plan|service)/.test(text);
  const support = /(how|help|setup|configure|login|support|error|integrate)/.test(text);
  let inquiryType = "question";
  if (complaint) inquiryType = "complaint";
  else if (order) inquiryType = "order";
  else if (sales) inquiryType = "sales_lead";
  else if (support) inquiryType = "support_ticket";
  const priority = complaint ? "high" : sales ? "medium" : "low";
  return {
    inquiryType,
    priority,
    sentiment: complaint ? "negative" : "neutral",
    language: "en",
    needsResearch: true,
    needsHuman: complaint && /(refund|legal|angry|cancel)/.test(text),
    confidence: 0.66,
    reason: "Fallback keyword classifier used because the model response was unavailable or invalid."
  };
}
const state = getPreviousState();
const response = $input.first().json;
const parsed = parseJsonLoose(contentFromResponse(response)) || fallbackClassifier(state);
const classifier = {
  inquiryType: parsed.inquiryType || "other",
  priority: parsed.priority || "medium",
  sentiment: parsed.sentiment || "neutral",
  language: parsed.language || "en",
  needsResearch: parsed.needsResearch !== false,
  needsHuman: Boolean(parsed.needsHuman),
  confidence: Math.max(0, Math.min(1, Number(parsed.confidence ?? 0.5))),
  reason: parsed.reason || "Classified inquiry."
};
state.classifier = classifier;
state.trace.push({ agent: "Classifier", step: "Classify inquiry", status: "ok", at: new Date().toISOString(), decision: classifier.reason, output: classifier });
return [{ json: { state } }];

const state = $input.first().json.state;
const system = `You are the Researcher Agent for ${state.config.businessName}. Use only the supplied knowledge base and business context. If data is missing, say what is missing. Return only valid JSON.`;
const user = {
  task: "Research the best grounded answer for the customer inquiry.",
  businessContext: state.config.businessContext,
  inquiry: { subject: state.subject, message: state.message, classifier: state.classifier },
  knowledgeBase: state.knowledgeBase,
  requiredJsonSchema: {
    answerFound: "boolean",
    answerSummary: "short grounded answer",
    sources: [{ title: "string", snippet: "string" }],
    missingInfo: ["string"],
    confidence: "number 0 to 1"
  }
};
const ollamaRequest = { model: state.config.ollamaModel, stream: false, format: "json", messages: [{ role: "system", content: system }, { role: "user", content: JSON.stringify(user) }] };
return [{ json: { state, ollamaRequest } }];

function getPreviousState() {
  try { return $items("Prepare Researcher Prompt")[0].json.state; } catch (error) { return $input.first().json.state || {}; }
}
function contentFromResponse(response) {
  if (response?.message?.content) return response.message.content;
  if (response?.response) return response.response;
  if (response?.data?.message?.content) return response.data.message.content;
  if (typeof response === "string") return response;
  return "";
}
function parseJsonLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch (error) {}
  const match = String(text).match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (error) {}
  }
  return null;
}
function fallbackResearcher(state) {
  const text = `${state.subject} ${state.message}`.toLowerCase();
  const scored = (state.knowledgeBase || []).map((doc) => {
    const hay = `${doc.title || ""} ${doc.text || doc.content || ""}`.toLowerCase();
    const score = text.split(/\W+/).filter((w) => w.length > 3 && hay.includes(w)).length;
    return { doc, score };
  }).sort((a, b) => b.score - a.score);
  const top = scored.filter((x) => x.score > 0).slice(0, 3).map((x) => ({
    title: x.doc.title || "Knowledge item",
    snippet: String(x.doc.text || x.doc.content || "").slice(0, 240)
  }));
  return {
    answerFound: top.length > 0,
    answerSummary: top.length ? top.map((s) => s.snippet).join(" ") : "No exact knowledge base match was found. Ask a clarifying question and avoid guessing.",
    sources: top,
    missingInfo: top.length ? [] : ["Relevant knowledge base article"],
    confidence: top.length ? 0.65 : 0.35
  };
}
const state = getPreviousState();
const parsed = parseJsonLoose(contentFromResponse($input.first().json)) || fallbackResearcher(state);
const researcher = {
  answerFound: Boolean(parsed.answerFound),
  answerSummary: parsed.answerSummary || "",
  sources: Array.isArray(parsed.sources) ? parsed.sources : [],
  missingInfo: Array.isArray(parsed.missingInfo) ? parsed.missingInfo : [],
  confidence: Math.max(0, Math.min(1, Number(parsed.confidence ?? 0.5)))
};
state.researcher = researcher;
state.trace.push({ agent: "Researcher", step: "Retrieve and ground answer", status: researcher.answerFound ? "ok" : "needs_info", at: new Date().toISOString(), decision: researcher.answerFound ? "Found usable support context." : "Missing reliable knowledge context.", output: researcher });
return [{ json: { state } }];

const state = $input.first().json.state;
const system = `You are the Qualifier Agent for ${state.config.businessName}. Score the inquiry as a lead/support request and decide escalation. Return only valid JSON.`;
const user = {
  task: "Qualify the inquiry and decide next action.",
  inquiry: { customer: state.customer, subject: state.subject, message: state.message },
  classifier: state.classifier,
  researcher: state.researcher,
  requiredJsonSchema: {
    leadScore: "integer 0 to 100",
    qualified: "boolean",
    urgency: "low|medium|high|urgent",
    nextAction: "send_reply|ask_clarifying_question|escalate_to_human",
    tags: ["string"],
    escalationReason: "string"
  }
};
const ollamaRequest = { model: state.config.ollamaModel, stream: false, format: "json", messages: [{ role: "system", content: system }, { role: "user", content: JSON.stringify(user) }] };
return [{ json: { state, ollamaRequest } }];

function getPreviousState() {
  try { return $items("Prepare Qualifier Prompt")[0].json.state; } catch (error) { return $input.first().json.state || {}; }
}
function contentFromResponse(response) {
  if (response?.message?.content) return response.message.content;
  if (response?.response) return response.response;
  if (response?.data?.message?.content) return response.data.message.content;
  if (typeof response === "string") return response;
  return "";
}
function parseJsonLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch (error) {}
  const match = String(text).match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (error) {}
  }
  return null;
}
function fallbackQualifier(state) {
  const type = state.classifier?.inquiryType || "other";
  const priority = state.classifier?.priority || "medium";
  const sales = type === "sales_lead";
  const needsHuman = Boolean(state.classifier?.needsHuman) || priority === "urgent";
  const leadScore = sales ? 72 : type === "complaint" ? 35 : 45;
  return {
    leadScore,
    qualified: sales && leadScore >= 60,
    urgency: priority,
    nextAction: needsHuman ? "escalate_to_human" : state.researcher?.answerFound ? "send_reply" : "ask_clarifying_question",
    tags: [type, priority].filter(Boolean),
    escalationReason: needsHuman ? "Classifier marked inquiry as requiring human review." : ""
  };
}
const state = getPreviousState();
const parsed = parseJsonLoose(contentFromResponse($input.first().json)) || fallbackQualifier(state);
const qualifier = {
  leadScore: Math.max(0, Math.min(100, Number(parsed.leadScore ?? 0))),
  qualified: Boolean(parsed.qualified),
  urgency: parsed.urgency || state.classifier?.priority || "medium",
  nextAction: parsed.nextAction || "send_reply",
  tags: Array.isArray(parsed.tags) ? parsed.tags : [],
  escalationReason: parsed.escalationReason || ""
};
state.qualifier = qualifier;
state.trace.push({ agent: "Qualifier", step: "Qualify and route", status: "ok", at: new Date().toISOString(), decision: qualifier.nextAction, output: qualifier });
return [{ json: { state } }];

const state = $input.first().json.state;
const system = `You are the Responder Agent for ${state.config.businessName}. Draft a reply for the original channel. Be ${state.config.tone}. Do not invent facts. Keep under ${state.config.maxReplyWords} words. Return only valid JSON.`;
const user = {
  task: "Draft a customer-ready response.",
  customer: state.customer,
  source: state.source,
  subject: state.subject,
  message: state.message,
  classifier: state.classifier,
  research: state.researcher,
  qualifier: state.qualifier,
  requiredJsonSchema: {
    finalReply: "string",
    replySubject: "string",
    needsHumanReview: "boolean",
    confidence: "number 0 to 1",
    rationale: "short string"
  }
};
const ollamaRequest = { model: state.config.ollamaModel, stream: false, format: "json", messages: [{ role: "system", content: system }, { role: "user", content: JSON.stringify(user) }] };
return [{ json: { state, ollamaRequest } }];

function getPreviousState() {
  try { return $items("Prepare Responder Prompt")[0].json.state; } catch (error) { return $input.first().json.state || {}; }
}
function contentFromResponse(response) {
  if (response?.message?.content) return response.message.content;
  if (response?.response) return response.response;
  if (response?.data?.message?.content) return response.data.message.content;
  if (typeof response === "string") return response;
  return "";
}
function parseJsonLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch (error) {}
  const match = String(text).match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (error) {}
  }
  return null;
}
function fallbackResponder(state) {
  const name = state.customer?.name || "there";
  const research = state.researcher?.answerSummary || "";
  const missing = state.researcher?.missingInfo || [];
  const greeting = state.source === "whatsapp" ? `Hi ${name},` : `Hi ${name},`;
  let body;
  if (state.qualifier?.nextAction === "escalate_to_human") {
    body = `${greeting}\n\nThanks for reaching out. I’ve received your message and I’m going to have the right person review it so we can respond accurately. We’ll follow up with you as soon as possible.\n\nBest,\n${state.config.businessName}`;
  } else if (missing.length) {
    body = `${greeting}\n\nThanks for your message. I can help with this, but I need one more detail before giving a complete answer: ${missing.join(", ")}.\n\nOnce you share that, I’ll guide you with the next step.\n\nBest,\n${state.config.businessName}`;
  } else {
    body = `${greeting}\n\nThanks for reaching out. ${research}\n\nPlease let me know if you’d like me to help with the next step.\n\nBest,\n${state.config.businessName}`;
  }
  return {
    finalReply: body,
    replySubject: state.subject?.startsWith("Re:") ? state.subject : `Re: ${state.subject || "Your inquiry"}`,
    needsHumanReview: state.qualifier?.nextAction === "escalate_to_human",
    confidence: state.researcher?.confidence || 0.55,
    rationale: "Fallback response drafted from classifier, researcher, and qualifier state."
  };
}
const state = getPreviousState();
const parsed = parseJsonLoose(contentFromResponse($input.first().json)) || fallbackResponder(state);
const responder = {
  finalReply: parsed.finalReply || fallbackResponder(state).finalReply,
  replySubject: parsed.replySubject || `Re: ${state.subject || "Your inquiry"}`,
  needsHumanReview: Boolean(parsed.needsHumanReview || state.qualifier?.nextAction === "escalate_to_human"),
  confidence: Math.max(0, Math.min(1, Number(parsed.confidence ?? 0.5))),
  rationale: parsed.rationale || "Drafted final reply."
};
state.responder = responder;
state.trace.push({ agent: "Responder", step: "Draft response", status: responder.needsHumanReview ? "needs_review" : "ok", at: new Date().toISOString(), decision: responder.rationale, output: { replySubject: responder.replySubject, finalReply: responder.finalReply, needsHumanReview: responder.needsHumanReview, confidence: responder.confidence } });
return [{ json: { state } }];

const state = $input.first().json.state;
const started = new Date(state.receivedAt).getTime();
const durationMs = Date.now() - started;
const agentConfidence = [
  state.classifier?.confidence ?? 0.5,
  state.researcher?.confidence ?? 0.5,
  state.responder?.confidence ?? 0.5
];
const avgConfidence = agentConfidence.reduce((a, b) => a + b, 0) / agentConfidence.length;
const missingPenalty = (state.researcher?.missingInfo?.length || 0) * 1.25;
const humanPenalty = state.responder?.needsHumanReview ? 1.5 : 0;
const score = Math.max(1, Math.min(10, Math.round((avgConfidence * 10) - missingPenalty - humanPenalty)));
const sendReady = Boolean(state.config.allowSend && !state.responder?.needsHumanReview);
const finalStatus = state.responder?.needsHumanReview ? "needs_human_review" : sendReady ? "ready_to_send" : "draft_only";
const bottlenecks = [];
if ((state.researcher?.missingInfo || []).length) bottlenecks.push("Knowledge base missing required details");
if (state.responder?.needsHumanReview) bottlenecks.push("Human review required before sending");
if (durationMs > 30000) bottlenecks.push("Handling time above 30 seconds");
const perAgentPerformance = {
  classifier: { score: Math.round((state.classifier?.confidence ?? 0.5) * 10), output: state.classifier },
  researcher: { score: Math.round((state.researcher?.confidence ?? 0.5) * 10), output: state.researcher },
  qualifier: { score: state.qualifier?.nextAction ? 8 : 5, output: state.qualifier },
  responder: { score: Math.round((state.responder?.confidence ?? 0.5) * 10), output: { needsHumanReview: state.responder?.needsHumanReview, rationale: state.responder?.rationale } }
};
const logRow = {
  runId: state.runId,
  receivedAt: state.receivedAt,
  completedAt: new Date().toISOString(),
  source: state.source,
  customerName: state.customer?.name || "",
  customerContact: state.customer?.contact || "",
  subject: state.subject,
  messageSnippet: state.message.slice(0, 180),
  inquiryType: state.classifier?.inquiryType || "other",
  priority: state.classifier?.priority || "medium",
  sentiment: state.classifier?.sentiment || "neutral",
  finalStatus,
  successScore: score,
  durationMs,
  finalReply: state.responder?.finalReply || ""
};
state.executor = { finalStatus, sendReady, logRow };
state.scorecard = {
  overallSuccessRating: score,
  success: score >= 7 && !state.responder?.needsHumanReview,
  responseQuality: {
    relevance: Math.round((state.researcher?.confidence ?? 0.5) * 10),
    completeness: Math.max(1, 10 - ((state.researcher?.missingInfo?.length || 0) * 2)),
    tone: 8
  },
  perAgentPerformance,
  bottlenecks,
  averageHandlingTimeMs: durationMs
};
state.trace.push({ agent: "Executor", step: "Prepare channel action and log row", status: "ok", at: new Date().toISOString(), decision: finalStatus, output: { sendReady, finalStatus, score } });
return [{
  json: {
    ok: true,
    workflow: "MVP Multi-Agent Customer Inquiry Handler",
    runId: state.runId,
    status: finalStatus,
    source: state.source,
    reply: {
      channel: state.source,
      to: state.customer?.contact || "",
      subject: state.responder?.replySubject || "",
      body: state.responder?.finalReply || "",
      sendReady,
      sendSkippedReason: sendReady ? "" : "The workflow is in safe draft mode or needs human review. Add Gmail/WhatsApp send nodes after credentials are configured."
    },
    scorecard: state.scorecard,
    analytics: {
      inquiryType: logRow.inquiryType,
      priority: logRow.priority,
      successScore: score,
      durationMs
    },
    logRow,
    trace: state.trace,
    productionNextStep: "Connect Gmail Trigger, WhatsApp Trigger, Google Drive retrieval, Google Sheets Append Row, and channel-specific send nodes after credentials are available."
  }
}];
